const cfgRows = $('Load Config Cache').all().map(i=>i.json);
const cfg = {}; for (const r of cfgRows){ if(r.key){ const p=String(r.key).split('.'); let c=cfg; for(let i=0;i<p.length-1;i++){c[p[i]]=c[p[i]]||{};c=c[p[i]];} c[p[p.length-1]]=r.value; } }
const chunkCfg = { chunking: { maxChars: (cfg.repository&&cfg.repository.chunking&&cfg.repository.chunking.maxChars)||1200 } };
const out = sw012_chunkBuilder({ acceptedUnits: $json.accepted }, chunkCfg);
return [{ json: { ...$json, chunks: out.chunks } }];

