function sw010_citationGenerator({ evidence, documentId }) {
  if (!documentId) throw new Error('SW-010: documentId is required (R-06)');
  const citations = evidence.map((ev) => ({
    id: uuidV4(),
    evidenceId: ev.id, // R-06
