const j = $json;
return [{ json: { status:'FAILED', documentId:j.documentId||null, stage:j.failStage||null,
  error:j.error||'stage failed',
  summary:{ workflow:'WF-001', executionId:j.correlationId, status:'FAILED', duration:(j.durationMs||0)+'ms',
    documentsProcessed:j.documentId?1:0, knowledgeUnits:0, evidenceObjects:0, chunks:0, embeddings:0, cost:0 } } }];

// Postgres nodes (SW-003 dup-check, SW-004 register) emit a fresh item without binary.
// SW-005 OCR needs the file. Re-attach the ENTIRE binary object from Download File so all
// metadata (filename, mimeType, filesystem-mode storage pointer, etc.) is preserved.
// json passes through unchanged.
return [{
  json: $json,
  binary: $('Download File').first().binary
}];
